import getpass
import psycopg2
from psycopg2 import Error

def install_extension():
    user_input = input("Enter extension name (e.g., plpgsql, plpythonu): ")
    try:
        conn = psycopg2.connect(
            host="localhost",
            database="your_database_name",
            user=getpass.getuser(),
            password=getpass.getpass())
        
        cur = conn.cursor()
        command = "CREATE EXTENSION IF NOT EXISTS {};".format(user_input)
        print("Running: {}".format(command))
        cur.execute(command)

        if cur.statusmessage == 'EXTENSION "{}" already exists':
            print("Extension '{}' is already installed.".format(user_input))

        elif user_input in ['plpythonu']:
            enable_plpythonu = input("Do you want to enable PL/Python? (y/n): ")
            if enable_plpythonu.lower() == "y":
                command = "ALTER SYSTEM SET shared_preload_libraries = 'plpython3u';"
                print("Running: {}".format(command))
                cur.execute(command)
        
        conn.commit()
        cur.close()
        print("Extension '{}' installed successfully.".format(user_input))

    except psycopg2.Error as e:
        print(e)

install_extension()